class Solution:
    def findXSum(self, nums, k, x):
        n = len(nums)
        res = []
        for i in range(n - k + 1):
            window = nums[i:i + k]
            freq = {}
            for v in window:
                freq[v] = freq.get(v, 0) + 1
            used = set()
            total = 0
            for _ in range(min(x, len(freq))):
                best_val = None
                best_cnt = -1
                for v, c in freq.items():
                    if v in used:
                        continue
                    if c > best_cnt or (c == best_cnt and (best_val is None or v > best_val)):
                        best_cnt = c
                        best_val = v
                used.add(best_val)
                total += best_val * best_cnt
            res.append(total)
        return res

