var findXSum = function(nums, k, x) {
    class Heap {
        constructor(cmp) { this.d = []; this.cmp = cmp; }
        size() { return this.d.length; }
        peek() { return this.d[0]; }
        push(item) {
            const d = this.d;
            d.push(item);
            let i = d.length - 1;
            while (i > 0) {
                const p = (i - 1) >> 1;
                if (this.cmp(d[i], d[p]) < 0) { [d[i], d[p]] = [d[p], d[i]]; i = p; }
                else break;
            }
        }
        pop() {
            const d = this.d;
            const top = d[0];
            const last = d.pop();
            if (d.length) {
                d[0] = last;
                let i = 0;
                const n = d.length;
                while (true) {
                    let l = 2 * i + 1, r = 2 * i + 2, s = i;
                    if (l < n && this.cmp(d[l], d[s]) < 0) s = l;
                    if (r < n && this.cmp(d[r], d[s]) < 0) s = r;
                    if (s === i) break;
                    [d[i], d[s]] = [d[s], d[i]];
                    i = s;
                }
            }
            return top;
        }
    }

    const cnt = new Map();
    const state = new Map();
    const inHeap = new Heap((a, b) => (a[0] !== b[0] ? a[0] - b[0] : a[1] - b[1]));
    const outHeap = new Heap((a, b) => (a[0] !== b[0] ? b[0] - a[0] : b[1] - a[1]));
    let total = 0;
    let inSize = 0;

    function pruneIn() {
        while (inHeap.size() > 0) {
            const [c, v] = inHeap.peek();
            if (state.get(v) === 'in' && cnt.get(v) === c) return;
            inHeap.pop();
        }
    }
    function pruneOut() {
        while (outHeap.size() > 0) {
            const [c, v] = outHeap.peek();
            if (state.get(v) === 'out' && cnt.get(v) === c) return;
            outHeap.pop();
        }
    }
    function rebalance() {
        const target = Math.min(x, cnt.size);
        while (inSize < target) {
            pruneOut();
            const [c, v] = outHeap.pop();
            state.set(v, 'in');
            inHeap.push([c, v]);
            total += c * v;
            inSize += 1;
        }
        while (inSize > target) {
            pruneIn();
            const [c, v] = inHeap.pop();
            state.set(v, 'out');
            outHeap.push([c, v]);
            total -= c * v;
            inSize -= 1;
        }
        while (true) {
            pruneIn();
            pruneOut();
            if (inHeap.size() === 0 || outHeap.size() === 0) break;
            const [ic, iv] = inHeap.peek();
            const [oc, ov] = outHeap.peek();
            if (oc > ic || (oc === ic && ov > iv)) {
                inHeap.pop();
                outHeap.pop();
                state.set(iv, 'out');
                state.set(ov, 'in');
                outHeap.push([ic, iv]);
                inHeap.push([oc, ov]);
                total += oc * ov - ic * iv;
            } else break;
        }
    }
    function add(val) {
        const old = cnt.get(val) || 0;
        const nw = old + 1;
        cnt.set(val, nw);
        if (old === 0) {
            state.set(val, 'out');
            outHeap.push([nw, val]);
        } else if (state.get(val) === 'in') {
            total += val;
            inHeap.push([nw, val]);
        } else {
            outHeap.push([nw, val]);
        }
        rebalance();
    }
    function remove(val) {
        const old = cnt.get(val);
        const nw = old - 1;
        if (nw === 0) {
            cnt.delete(val);
            if (state.get(val) === 'in') {
                total -= val * old;
                inSize -= 1;
            }
            state.delete(val);
        } else {
            cnt.set(val, nw);
            if (state.get(val) === 'in') {
                total -= val;
                inHeap.push([nw, val]);
            } else {
                outHeap.push([nw, val]);
            }
        }
        rebalance();
    }

    const n = nums.length;
    const res = [];
    for (let i = 0; i < n; i++) {
        add(nums[i]);
        if (i >= k) remove(nums[i - k]);
        if (i >= k - 1) res.push(total);
    }
    return res;
};
